SELECT a.poid_id0, a.pipeline_name, a.recycle_mode, a.override_reasons, a.batch_id, a.suspended_from_batch_id, a.recycle_key, a.edr_buf, a.editable_flds from ( SELECT b.poid_id0 , b.pipeline_name, r.recycle_mode, r.override_reasons,b.batch_id, b.suspended_from_batch_id, b.recycle_key, e.edr_buf,'A_NUMBER='|| t.calling_from|| CHR (9)|| 'B_NUMBER='|| t.called_to|| CHR (9)|| 'DURATION='|| t.call_duration|| CHR (9)|| 'CHARGING_START_TIMESTAMP='|| t.start_time|| CHR (9)|| 'USAGE_TYPE='|| t.usage_type|| CHR (9)|| 'BASIC_SERVICE='|| t.service_type|| CHR (9)|| 'VOLUME_RECEIVED='|| t.bytes_in|| CHR (9)|| 'VOLUME_SENT='|| t.bytes_out|| CHR (9)|| 'ASS_GSMW_EXT.PORT_NUMBER='|| g.secondary_msid||  CHR (9)|| 'ASS_GSMW_EXT.DIALED_DIGITS='|| g.dialed_number|| CHR (9)|| 'ASS_GSMW_EXT.CELL_ID='|| g.cell_id|| CHR (9) || 'ASS_GSMW_EXT.ORIGINATING_SWITCH_IDENTIFICATION='|| g.origin_sid|| CHR (9)|| 'ASS_GSMW_EXT.TERMINATING_SWITCH_IDENTIFICATION='|| g.destination_sid as editable_flds FROM suspended_usage_t b,susp_usage_telco_info_t t,susp_usage_telco_gsm_info_t g,susp_usage_edr_buf e,susp_usage_recycle_t r WHERE b.poid_id0 = t.obj_id0 AND b.poid_id0 = e.obj_id0 AND b.recycle_obj_id0 = r.obj_id0 AND b.poid_id0 = g.obj_id0 AND b.recycle_obj_id0 = ${RECYCLE_JOB_ID} AND NVL(b.pipeline_category,'NULL') = ${PIPELINE_CATEGORY} UNION ALL SELECT b.poid_id0, b.pipeline_name, r.recycle_mode, r.override_reasons, b.batch_id, b.suspended_from_batch_id, b.recycle_key,  e.edr_buf,'A_NUMBER='|| t.calling_from|| CHR (9) || 'B_NUMBER='|| t.called_to|| CHR (9)|| 'DURATION='|| t.call_duration|| CHR (9)|| 'CHARGING_START_TIMESTAMP='|| t.start_time|| CHR (9) || 'USAGE_TYPE='|| t.usage_type|| CHR (9)|| 'BASIC_SERVICE='|| t.service_type|| CHR (9)|| 'VOLUME_RECEIVED='|| t.bytes_in|| CHR (9) || 'VOLUME_SENT='|| t.bytes_out|| CHR (9)|| 'ASS_GPRS_EXT.SGSN_ADDRESS='|| p.sgsn_address|| CHR (9)|| 'ASS_GPRS_EXT.GGSN_ADDRESS='|| p.GGSN_ADDRESS|| CHR (9)|| 'ASS_GPRS_EXT.APN_ADDRESS='|| p.apn|| CHR (9)|| 'ASS_GPRS_EXT.NODE_ID='|| p.node_id as editable_flds FROM suspended_usage_t b,susp_usage_telco_info_t t,susp_usage_telco_gprs_info_t p,susp_usage_edr_buf e,susp_usage_recycle_t r WHERE b.poid_id0 = t.obj_id0 AND b.poid_id0 = e.obj_id0 AND b.recycle_obj_id0 = r.obj_id0 AND b.poid_id0 = p.obj_id0 AND b.recycle_obj_id0 = ${RECYCLE_JOB_ID} AND NVL(b.pipeline_category,'NULL') = ${PIPELINE_CATEGORY}) a ORDER BY a.poid_id0
